import React, { useEffect, useState } from 'react';
import AppLayout from '../../components/shared/AppLayout';
import LoadingSpinner from '../../components/shared/LoadingSpinner';
import api from '../../utils/api';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';

const StatCard = ({ label, value, icon, color = 'text-white' }) => (
  <div className="stat-card">
    <div className="flex items-start justify-between">
      <div>
        <div className={`stat-number ${color}`}>{value}</div>
        <div className="stat-label mt-1">{label}</div>
      </div>
      <span className="text-2xl opacity-60">{icon}</span>
    </div>
  </div>
);

const COLORS = ['#3d8b3d', '#c9a20d', '#4a4f5b', '#e57b3d', '#7a5f09'];

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/admin/stats')
      .then(r => setStats(r.data.stats))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return (
    <AppLayout>
      <div className="flex justify-center mt-20"><LoadingSpinner size="lg" text="Loading analytics..." /></div>
    </AppLayout>
  );

  const subData = stats.subscriptionBreakdown.map(s => ({
    name: s._id ? (s._id.charAt(0).toUpperCase() + s._id.slice(1)) : 'Unknown',
    value: s.count
  }));

  const charityData = stats.charityContributions.map(c => ({
    name: c.charity?.name?.split(' ').slice(0, 2).join(' ') || 'Unknown',
    users: c.count,
    avg: Math.round(c.avg_percentage)
  }));

  return (
    <AppLayout>
      <div className="max-w-6xl mx-auto space-y-8 animate-slide-up">
        <div>
          <h1 className="page-title">Admin Overview</h1>
          <p className="text-charcoal-400 mt-1">Platform analytics and management</p>
        </div>

        {/* Stats grid */}
        <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4">
          <StatCard label="Total Users" value={stats.totalUsers} icon="👥" />
          <StatCard label="Active Subscribers" value={stats.activeSubscribers} icon="✦" color="text-forest-400" />
          <StatCard label="Total Draws" value={stats.totalDraws} icon="🎲" />
          <StatCard label="Published Draws" value={stats.publishedDraws} icon="📢" color="text-gold-400" />
          <StatCard label="Total Winners" value={stats.totalWinners} icon="🏆" color="text-gold-400" />
          <StatCard label="Charities" value={stats.totalCharities} icon="💚" color="text-forest-400" />
        </div>

        {/* Charts row */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Subscription breakdown */}
          <div className="card">
            <h2 className="section-title mb-6">Subscription Plans</h2>
            {subData.length === 0 ? (
              <p className="text-charcoal-500 text-sm text-center py-8">No active subscriptions</p>
            ) : (
              <ResponsiveContainer width="100%" height={200}>
                <PieChart>
                  <Pie
                    data={subData}
                    cx="50%"
                    cy="50%"
                    innerRadius={55}
                    outerRadius={80}
                    paddingAngle={4}
                    dataKey="value"
                  >
                    {subData.map((_, i) => (
                      <Cell key={i} fill={COLORS[i % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip
                    contentStyle={{ background: '#1e2028', border: '1px solid #3d414b', borderRadius: '8px', fontFamily: 'DM Sans' }}
                    labelStyle={{ color: '#e2e3e6' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            )}
            <div className="flex flex-wrap gap-3 mt-2 justify-center">
              {subData.map((s, i) => (
                <div key={i} className="flex items-center gap-1.5">
                  <div className="w-3 h-3 rounded-full" style={{ background: COLORS[i % COLORS.length] }} />
                  <span className="text-xs text-charcoal-400">{s.name}: {s.value}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Charity contributions */}
          <div className="card">
            <h2 className="section-title mb-6">Charity Support</h2>
            {charityData.length === 0 ? (
              <p className="text-charcoal-500 text-sm text-center py-8">No charity selections yet</p>
            ) : (
              <ResponsiveContainer width="100%" height={220}>
                <BarChart data={charityData} margin={{ top: 5, right: 5, bottom: 40, left: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#333740" />
                  <XAxis
                    dataKey="name"
                    tick={{ fill: '#9fa3ab', fontSize: 10, fontFamily: 'DM Sans' }}
                    angle={-25}
                    textAnchor="end"
                  />
                  <YAxis tick={{ fill: '#9fa3ab', fontSize: 11, fontFamily: 'DM Sans' }} />
                  <Tooltip
                    contentStyle={{ background: '#1e2028', border: '1px solid #3d414b', borderRadius: '8px', fontFamily: 'DM Sans' }}
                  />
                  <Bar dataKey="users" fill="#3d8b3d" radius={[4, 4, 0, 0]} name="Users" />
                </BarChart>
              </ResponsiveContainer>
            )}
          </div>
        </div>

        {/* Quick links */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {[
            { label: 'Manage Users', desc: 'View and edit user accounts', href: '/admin/users', icon: '👥', color: 'hover:border-forest-700/60' },
            { label: 'Run Draw', desc: 'Generate and publish monthly draws', href: '/admin/draws', icon: '🎲', color: 'hover:border-gold-700/60' },
            { label: 'View Winners', desc: 'See all prize winners', href: '/admin/winners', icon: '🏆', color: 'hover:border-gold-700/60' },
            { label: 'Manage Charities', desc: 'Add or edit charity options', href: '/admin/charities', icon: '💚', color: 'hover:border-forest-700/60' },
          ].map((item, i) => (
            <a key={i} href={item.href} className={`card-hover ${item.color} transition-all`}>
              <div className="text-2xl mb-3">{item.icon}</div>
              <h3 className="font-display font-semibold text-white mb-1">{item.label}</h3>
              <p className="text-xs text-charcoal-500">{item.desc}</p>
            </a>
          ))}
        </div>
      </div>
    </AppLayout>
  );
}
